#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define grep(a,b,c) for(int c=a.head[(b)];c;c=a.nxt[c])
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const int N=1e6+10, M=2e6+10;
struct SAM
{
	struct node
	{
		int ch[26], len, fa;
	}t[N];
	struct Graph
	{
		int head[N], des[M], nxt[M], cnt;
		inline void ins(int x,int y){nxt[++cnt]=head[x];des[cnt]=y;head[x]=cnt;}
	}a;
	int cnt, lst, res[N];
	int stk[N], top;
	bool flag;
	inline void ins(int c)
	{
		int p=lst, np=lst=++cnt; siz[np]=1;
		t[np].len=t[p].len+1;
		res[np]=1;
 		for(;p&&!t[p].ch[c];p=t[p].fa)t[p].ch[c]=np;
 		if(!p)t[np].fa=1;
 		else
 		{
 			int v=t[p].ch[c];
 			if(t[v].len==t[p].len+1)t[np].fa=v;
 			else
 			{
 				int nv=++cnt; t[nv]=t[v];
 				t[nv].len=t[p].len+1;
 				for(;p&&t[p].ch[c]==v;p=t[p].fa)t[p].ch[c]=nv;
 				t[np].fa=t[v].fa=nv;
			}
		}
	}
	int T[N],A[N],siz[N],sum[N];
	void dfs(int x,int k)
	{
		if(k<=siz[x]) return;k-=siz[x];rep(0,25,i)
		{
			int R=t[x].ch[i]; if(!R)continue;
			if(k>sum[R]){k-=sum[R];continue;}
			putchar(i+'a');dfs(R,k);return;
		}
	}
	inline void INIT(bool tmp,int kk)
	{
		rep(1,cnt,i) T[t[i].len]++;
		rep(1,cnt,i) T[i]+=T[i-1];
		rep(1,cnt,i) A[T[t[i].len]--]=i;
		drep(cnt,1,i) siz[t[A[i]].fa]+=siz[A[i]];
		rep(1,cnt,i) !tmp?(sum[i]=siz[i]=1):(sum[i]=siz[i]);siz[1]=sum[1]=0;
		drep(cnt,1,i)rep(0,25,j)if(t[A[i]].ch[j])sum[A[i]]+=sum[t[A[i]].ch[j]];
		if(sum[1]<kk) puts("-1");else dfs(1,kk),puts("");
	}
}Sam;
char s[N];
int main()
{
// 	freopen("dtt.txt","r",stdin);
	scanf("%s",s);
	int len=strlen(s);
//	printf("%d\n",len);
	Sam.cnt=Sam.lst=1;
	rep(0,len-1,i)Sam.ins(s[i]-'a');
	bool t=read();int k=read();
	Sam.INIT(t,k);
	
}
